switch itemIdentifier {
    case .followButton:
      return makeFollowButton()
    case .logLevelButton:
      return makeLogLevelButton()
    case .subsystemButton:
      return makeSubsystemButton()
    case .saveButton:
      return makeSaveButton()
    case .searchField:
      return makeSearchField()
    default:
      return nil
    }

Logger.$subsystems.withLock() { subsystems in
      for (index, subsystem) in subsystems.enumerated() {
        guard !subsystem.added else { continue }
        subsystem.added = true
        let item = NSMenuItem.init(title: subsystem.rawValue, action: #selector(subsystemChanged), keyEquivalent: "")
        item.image = subsystem.image
        // 3 = dummy + clear selection item + separator
        menu.insertItem(item, at: index + 3)
      }
    }

filteredSubsystems = []
    if #available(macOS 14.0, *) {
      subsystemMenu.selectedItems = []
    } else {
      subsystemMenu.items.forEach { $0.state = .off }
    }

if filteredSubsystems.contains(sender.title) {
      sender.state = .off
      filteredSubsystems.remove(sender.title)
    } else {
      sender.state = .on
      filteredSubsystems.insert(sender.title)
    }

guard let newLevel = Logger.Level(rawValue: sender.tag) else { return }
    filteredLogLevel = newLevel
    updateLogLevelButtonImage()

var predicates: [NSPredicate] = []
    if !filteredSubsystems.isEmpty {
      let subsystemPredicate = NSCompoundPredicate(orPredicateWithSubpredicates: filteredSubsystems.map {
          NSPredicate(format: "subsystem == %@", $0)
      })
      predicates.append(subsystemPredicate)
    }
    predicates.append(NSPredicate(format: "level >= %d", filteredLogLevel.rawValue))
    if !filterString.isEmpty {
      predicates.append(NSPredicate(format: "message CONTAINS[c] %@", filterString))
    }
    predicate = NSCompoundPredicate(andPredicateWithSubpredicates: predicates)

let item = toolBarItem ?? toolbarItem(withID: .logLevelButton)
    if let item {
      item.image = indicatorIcon(withColor: filteredLogLevel.color).withSymbolConfiguration(.init(scale: .medium))
    }

guard tableView.numberOfRows > 0 else { return }
    // Force layout so auto row heights are up to date before scrolling.
    tableView.layoutSubtreeIfNeeded()
    tableView.scrollRowToVisible(tableView.numberOfRows - 1)

let saveAll = sender is NSToolbarItem
    let filename = saveAll ? "iina.log" : (window?.subtitle ?? "filtered") + " iina.log"
    Utility.quickSavePanel(title: "Log", filename: filename, sheetWindow: window) { url in
      let content: Any? = saveAll ? self.arrayController.content : self.arrayController.arrangedObjects
      let logs = (content as! [Logger.Log]).map { $0.logString }.joined()
      do {
        try logs.write(to: url, atomically: true, encoding: .utf8)
      } catch let error {
        Utility.showAlert("error_saving_file", arguments: [NSLocalizedString("logwindow.logs", comment: "logs"), error.localizedDescription])
      }
    }

$buffer.withLock {
      $0.append(log)
    }
    if isWindowVisible {
      scheduleFlush()
    }

guard flushTimer == nil else { return }
    flushTimer = Timer.scheduledTimer(withTimeInterval: 0.1, repeats: false) { [weak self] _ in
      self?.flushTimer = nil
      self?.flushBuffer()
    }

let toFlush: [Logger.Log] = $buffer.withLock {
      let copy = $0
      $0.removeAll(keepingCapacity: true)
      return copy
    }

    if !toFlush.isEmpty {
      checkIfAtBottom()
      logs.append(contentsOf: toFlush)
      if following {
        scrollToBottom()
      }
    }

if isWindowVisible {
      flushBuffer()
    } else {
      flushTimer = nil
    }

guard let button = toolbarItem(withID: .followButton) else { return }
      let symbolName = following ? "arrow.up.left.circle.fill" : "arrow.up.left.circle"
      button.image = .sf(symbolName)

guard let window else { return }
      var subtitleString = ""
      if filteredSubsystems.isEmpty {
        subtitleString = NSLocalizedString("logwindow.all_subsystems", comment: "All subsystems")
      } else {
        subtitleString = String(describing: filteredSubsystems)
      }
      subtitleString += " - "
      subtitleString += String(describing: filteredLogLevel)
      window.subtitle = subtitleString

switch self {
      case .verbose: return "verbose"
      case .debug: return "debug"
      case .warning: return "warning"
      case .error: return "error"
      }

switch self {
      case .verbose: return "v"
      case .debug: return "d"
      case .warning: return "w"
      case .error: return "e"
      }

switch self {
      case .verbose: return .systemGray
      case .debug: return .systemGreen
      case .warning: return .systemYellow
      case .error: return .systemRed
      }

$subsystems.withLock() { subsystems in
      for (index, subsystem) in subsystems.enumerated() {
        // The first subsystem will always be "iina"
        if index == 0 { continue }
        if rawValue < subsystem.rawValue {
          let newSubsystem = Subsystem(rawValue: rawValue, symbolName: symbolName)
          subsystems.insert(newSubsystem, at: index)
          return newSubsystem
        } else if rawValue == subsystem.rawValue {
          return subsystem
        }
      }
      let newSubsystem = Subsystem(rawValue: rawValue, symbolName: symbolName)
      subsystems.append(newSubsystem)
      return newSubsystem
    }

guard enabled else { return }
    // Lock to avoid closing the log file while another thread is writing to it.
    lock.withLock {
      guard let fileHandle = logFileHandle else { return }
      do {
        // The deprecated method is used instead of the new close method that throws swift exceptions
        // because testing with the new write method found it failed to convert all objective-c
        // exceptions to swift exceptions.
        try ObjcUtils.catchException { fileHandle.closeFile() }
      } catch {
        // Unusual, but could happen if closing causes a buffer to be flushed to a full disk.
        print(formatMessage("Cannot close log file \(logFile.path): \(error.localizedDescription)",
                            .error, Logger.loggerSubsystem, true))
      }
      logFileHandle = nil
    }

do {
      try FileManager.default.createDirectory(at: url, withIntermediateDirectories: true, attributes: nil)
    } catch {
      fatalDuringInit("Cannot create directory \(url): \(error.localizedDescription)")
    }

#if !DEBUG
    guard enabled else { return }
    #endif

    guard level.rawValue >= Preference.integer(for: .logLevel) else { return }

    // Now that we know the message will not be discarded, call the closure to construct the message
    // string to log.
    let message = message()

    let date = Date()
    let string = formatMessage(message, level, subsystem, true, date)
    let log = Log(subsystem: subsystem.rawValue, level: level, message: message, date: dateFormatter.string(from: date), logString: string)

    $buffer.withLock {
      $0.append(log)
    }
    Task { @MainActor in
      NotificationCenter.default.post(name: .iinaLogAppended, object: nil)
    }

    print(string, terminator: "")

    #if DEBUG
    guard enabled else { return }
    #endif

    guard let data = string.data(using: .utf8) else {
      print(formatMessage("Cannot encode log string!", .error, Logger.loggerSubsystem, false))
      return
    }
    // Lock to prevent the log file from being closed by another thread while writing to it.
    lock.withLock() {
      // The logger may be called after it has been closed.
      guard let logFileHandle = logFileHandle else { return }
      do {
        // The deprecated write method is used instead of the replacement method that throws swift
        // exceptions because testing the new method with macOS 12.5.1 showed that method failed to
        // turn all objective-c exceptions into swift exceptions. The exception thrown for writing
        // to a closed channel was not picked up by the catch block.
        try ObjcUtils.catchException { logFileHandle.write(data) }
      } catch {
        print(formatMessage("Cannot write to log file: \(error.localizedDescription)", .error,
                            Logger.loggerSubsystem, false))
      }
    }

guard condition() else {
      log(errorMessage, level: .error)
      showAlertAndExit(errorMessage, cleanup)
    }

